const body = $input.first().json.body || $input.first().json;

const sessionId = body.session_id || `session_${Date.now()}`;
const userMessage = body.message || body.texto || '';
const conversationHistory = body.history || [];

if (!userMessage.trim()) {
  throw new Error('Mensaje vacío');
}

return [{
  json: {
    sessionId,
    userMessage,
    conversationHistory,
    timestamp: new Date().toISOString()
  }
}];

const aiResponse = $input.first().json.text || $input.first().json.content || '';
const inputData = $('Parsear Mensaje Entrante').first().json;

// Extraer datos de lead si existen
let leadData = null;
let appointmentData = null;
let cleanResponse = aiResponse;

const leadMatch = aiResponse.match(/<LEAD_DATA>([\s\S]*?)<\/LEAD_DATA>/);
if (leadMatch) {
  try {
    leadData = JSON.parse(leadMatch[1].trim());
    cleanResponse = aiResponse.replace(/<LEAD_DATA>[\s\S]*?<\/LEAD_DATA>/, '').trim();
  } catch(e) {}
}

const appointmentMatch = aiResponse.match(/<APPOINTMENT_DATA>([\s\S]*?)<\/APPOINTMENT_DATA>/);
if (appointmentMatch) {
  try {
    appointmentData = JSON.parse(appointmentMatch[1].trim());
    cleanResponse = cleanResponse.replace(/<APPOINTMENT_DATA>[\s\S]*?<\/APPOINTMENT_DATA>/, '').trim();
  } catch(e) {}
}

// Actualizar historial
const updatedHistory = [
  ...inputData.conversationHistory,
  { role: 'user', content: inputData.userMessage },
  { role: 'assistant', content: cleanResponse }
];

return [{
  json: {
    sessionId: inputData.sessionId,
    botResponse: cleanResponse,
    conversationHistory: updatedHistory,
    leadData,
    appointmentData,
    hasLeadData: !!leadData,
    hasAppointmentData: !!appointmentData,
    timestamp: new Date().toISOString()
  }
}];
